function delay(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function runSequence() {
  for (var i = 0; i < 3; i++) {
    delay(10).then(() => console.log('Then', i));
    (async function(j) {
      await delay(5);
      console.log('Await', j);
    })(i);
  }
  console.log('Loop done');
}

runSequence();
